import java.util.HashMap;
import java.util.Map;

public class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode() {}
    TreeNode(int val) { this.val = val; }
    TreeNode(int val, TreeNode left, TreeNode right) {
        this.val = val;
        this.left = left;
        this.right = right;
    }
}

class Solution {
    private int pre_idx = 0;
    private int[] preorder;
    private int[] inorder;
    private Map<Integer, Integer> in_map = new HashMap<>();

    public TreeNode buildTree(int[] preorder, int[] inorder) {
        this.preorder = preorder;
        this.inorder = inorder;
        for (int i = 0; i < inorder.length; i++) {
            in_map.put(inorder[i], i);
        }
        return constructTree(0, inorder.length - 1);
    }

    private TreeNode constructTree(int in_left, int in_right) {
        if (in_left > in_right) return null;

        int root_val = preorder[pre_idx];
        TreeNode root = new TreeNode(root_val);
        int idx = in_map.get(root_val);

        pre_idx++;
        root.left = constructTree(in_left, idx - 1);
        root.right = constructTree(idx + 1, in_right);

        return root;
    }
}
```

